import React, { useState } from 'react';
import Login from './pages/Login';
import Landing from './pages/Landing';
import Predictor from './pages/Predictor';
import Results from './pages/Results';

export default function App() {
  const [page, setPage]       = useState('landing');
  const [results, setResults] = useState(null);

  const handleResults = (data) => {
    setResults(data);
    setPage('results');
  };

  if (page === 'landing')   return <Landing   onStart={() => setPage('predictor')} />;
  if (page === 'predictor') return <Predictor onResults={handleResults} onBack={() => setPage('landing')} />;
  if (page === 'results')   return <Results   data={results} onReset={() => setPage('predictor')} />;
}
